import React, { useEffect, useState } from 'react';
import socketService from '../services/socketService';
import './RoomManager.css';

const RoomManager = ({ onRoomJoined, currentRoom, connectedUsers = [] }) => {
  const [showRoomDialog, setShowRoomDialog] = useState(false);
  const [roomId, setRoomId] = useState('');
  const [isConnected, setIsConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const checkConnection = () => {
      setIsConnected(socketService.getConnectionStatus());
    };

    const interval = setInterval(checkConnection, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleCreateRoom = async () => {
    setIsLoading(true);
    try {
      const newRoomId = await socketService.createRoom();
      handleJoinRoom(newRoomId);
    } catch (error) {
      console.error('Failed to create room:', error);
      alert('Failed to create room. Please try again.');
    }
    setIsLoading(false);
  };

  const handleJoinRoom = (targetRoomId = roomId) => {
    if (!targetRoomId.trim()) {
      alert('Please enter a room ID');
      return;
    }

    socketService.joinRoom(targetRoomId.toUpperCase());
    onRoomJoined(targetRoomId.toUpperCase());
    setShowRoomDialog(false);
    setRoomId('');
  };

  const handleLeaveRoom = () => {
    socketService.disconnect();
    onRoomJoined(null);
  };

  const copyRoomId = () => {
    if (currentRoom) {
      navigator.clipboard.writeText(currentRoom);
      alert('Room ID copied to clipboard!');
    }
  };

  return (
    <div className="room-manager">
      {/* Connection Status */}
      <div className={`connection-status ${isConnected ? 'connected' : 'disconnected'}`}>
        <div className="status-indicator"></div>
        <span>{isConnected ? 'Connected' : 'Disconnected'}</span>
      </div>

      {/* Room Controls */}
      {!currentRoom ? (
        <button 
          className="room-button primary"
          onClick={() => setShowRoomDialog(true)}
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
            <circle cx="9" cy="7" r="4"/>
            <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
            <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
          </svg>
          Join/Create Room
        </button>
      ) : (
        <div className="room-info">
          <div className="room-details">
            <span className="room-label">Room:</span>
            <span className="room-id" onClick={copyRoomId} title="Click to copy">
              {currentRoom}
            </span>
          </div>

          <div className="user-count">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
              <circle cx="9" cy="7" r="4"/>
              <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
              <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
            </svg>
            {connectedUsers.length} user{connectedUsers.length !== 1 ? 's' : ''}
          </div>

          <button 
            className="room-button secondary"
            onClick={handleLeaveRoom}
            title="Leave Room"
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
              <polyline points="16,17 21,12 16,7"/>
              <line x1="21" y1="12" x2="9" y2="12"/>
            </svg>
          </button>
        </div>
      )}

      {/* Room Dialog */}
      {showRoomDialog && (
        <div className="room-dialog-overlay">
          <div className="room-dialog">
            <h3>Join or Create Room</h3>

            <div className="dialog-content">
              <div className="input-group">
                <label>Enter Room ID (optional)</label>
                <input
                  type="text"
                  value={roomId}
                  onChange={(e) => setRoomId(e.target.value.toUpperCase())}
                  placeholder="e.g., ABC123"
                  maxLength={6}
                />
              </div>

              <div className="dialog-actions">
                <button 
                  className="dialog-button primary"
                  onClick={handleCreateRoom}
                  disabled={isLoading}
                >
                  {isLoading ? 'Creating...' : 'Create New Room'}
                </button>

                <button 
                  className="dialog-button secondary"
                  onClick={() => handleJoinRoom()}
                  disabled={!roomId.trim() || isLoading}
                >
                  Join Room
                </button>

                <button 
                  className="dialog-button"
                  onClick={() => setShowRoomDialog(false)}
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RoomManager;
